"use strict";(self.webpackChunkdocs=self.webpackChunkdocs||[]).push([[161],{6702:e=>{e.exports=JSON.parse('{"functions":[{"name":"new","desc":"Creates a new `Hover` instance. Does not start listening for hovers \u2014\\ncall [Hover:Start] to begin.","params":[{"name":"options","desc":"Optional initial config overrides, see [Hover.Configure]","lua_type":"table?"}],"returns":[{"desc":"","lua_type":"Hover"}],"function_type":"static","source":{"line":238,"path":"src/init.luau"}},{"name":"Configure","desc":"Overrides one or more values in [Hover.Config]. Valid keys are\\n`HoverRange`, `ContinuousHover`, and `Tag`. Unknown keys produce a warning\\nand are ignored.","params":[{"name":"options","desc":"A table of config keys to override","lua_type":"table"}],"returns":[],"function_type":"method","source":{"line":269,"path":"src/init.luau"}},{"name":"GetHovered","desc":"Returns the instance currently being hovered, or `nil` if nothing is hovered.","params":[],"returns":[{"desc":"The currently hovered instance, if any","lua_type":"Instance?"}],"function_type":"method","source":{"line":340,"path":"src/init.luau"}},{"name":"Init","desc":"Sets up tag observation so tagged instances become hoverable. Called\\nautomatically by [Hover:Start] if not already initialized \u2014 you generally\\ndon\'t need to call this yourself.","params":[],"returns":[],"function_type":"method","source":{"line":353,"path":"src/init.luau"}},{"name":"Start","desc":"Begins listening for mouse/touch/gamepad hovers over tagged instances.\\nCalls [Hover:Init] automatically if it hasn\'t run yet.","params":[],"returns":[],"function_type":"method","source":{"line":383,"path":"src/init.luau"}},{"name":"Stop","desc":"Stops listening for hovers and clears any current hover state, firing\\n[Hover.HoveringEnded] if something was being hovered.","params":[],"returns":[],"function_type":"method","source":{"line":401,"path":"src/init.luau"}},{"name":"Destroy","desc":"Stops the instance, disconnects all internal listeners, and destroys its\\nsignals. The `Hover` instance should not be used after calling this.","params":[],"returns":[],"function_type":"method","source":{"line":417,"path":"src/init.luau"}}],"properties":[],"types":[],"name":"Hover","desc":"Detects when the player\'s mouse (or touch/gamepad cursor) is hovering\\nover tagged instances in the 3D world, using a raycast from the camera.\\n\\nHoverable instances are marked using a CollectionService tag (configurable\\nvia `Config.Tag`, default `\\"Hoverable\\"`).\\n\\n:::info\\nThis module is client-only. Requiring it on the server returns an empty table.\\n:::\\n\\n```lua\\nlocal hover = Hover.new()\\nhover:Start()\\n\\nhover.HoveringStarted:Connect(function(instance)\\n\\tprint(\\"Started hovering:\\", instance:GetFullName())\\nend)\\n\\nhover.Clicked:Connect(function(instance)\\n\\tprint(\\"Clicked while hovering:\\", instance:GetFullName())\\nend)\\n```","source":{"line":71,"path":"src/init.luau"}}')}}]);